import { useEffect, useState } from "react";
import axios from "../api/axios";
import { useParams } from "react-router-dom";

export default function SlotList() {
  const { id } = useParams();
  const [slots, setSlots] = useState([]);

  const load = () => {
    axios.get(`/slots/${id}`).then(res => setSlots(res.data));
  };

  useEffect(load, []);

  const book = async (slotId) => {
    await axios.post("/bookings", { slotId });
    load();
  };

  return (
    <div className="container">
      <h2>Slots</h2>
      <div className="grid">
        {slots.map(s => (
          <div className={`card ${s.isBooked && "disabled"}`} key={s._id}>
            <h3>{s.slotNumber}</h3>
            <p>{s.isBooked ? "Booked" : "Available"}</p>
            {!s.isBooked && <button onClick={() => book(s._id)}>Book</button>}
          </div>
        ))}
      </div>
    </div>
  );
}
